def verify(output: str):
    # Check all constraints and collect failure messages
    failures = []

    # Total constraints: 5
    # Constraint 1: exactly 20 decimal digits
    if len(output) != 20:
        failures.append("Length must be exactly 20 digits")

    # Constraint 2: contains exactly 1 occurrence of substring "2026"
    count_2026 = output.count("2026")
    if count_2026 != 1:
        failures.append(f"Must contain exactly 1 occurrence of '2026' (found {count_2026})")

    # Constraint 3: no occurrence of "000"
    if "000" in output:
        failures.append("Must not contain '000'")

    # Constraint 4: must not start with '0'
    if output[0] == '0':
        failures.append("Must not start with '0'")

    # Constraint 5: must end with an odd digit
    odd_digits = {'1', '3', '5', '7', '9'}
    if output[-1] not in odd_digits:
        failures.append(f"Must end with an odd digit (ended with '{output[-1]}')")

    # Constraint 6: total number of even digits is exactly 10
    even_digits = {'0', '2', '4', '6', '8'}
    even_count = sum(1 for ch in output if ch in even_digits)
    if even_count != 10:
        failures.append(f"Must have exactly 10 even digits (found {even_count})")

    # Determine validity and compute score
    total_constraints = 6
    satisfied = total_constraints - len(failures)
    score = satisfied / total_constraints

    is_valid = len(failures) == 0

    # Build message
    if is_valid:
        message = "All constraints satisfied"
    else:
        message = "; ".join(failures)

    return (is_valid, score, message)
